/**
 * AUDIO DATA MODULE
 * Містить Base64 дані аудіо файлів для вирішення CORS проблем
 * Використовується замість локальних файлів для забезпечення сумісності
 */

// ===== BASE64 АУДІО ДАНІ =====

/**
 * Base64 дані аудіо файлів
 * Конвертовані з оригінальних MP3 файлів для уникнення CORS обмежень
 */
const AUDIO_BASE64_DATA = {
    // Звук обертання барабанів
    drumSpin: 'data:audio/mpeg;base64,',
    // Звук результату розіграшу
    resultDing: 'data:audio/mpeg;base64,',
    // Звук перемоги
    victoryFanfare: 'data:audio/mpeg;base64,'
};

window.AudioData = {
    getAudioData(key) {
        return AUDIO_BASE64_DATA[key] || null;
    }
};
